import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface AccountData {
  username: string;
  platform: string;
  followers: number;
  engagementRate: number;
}

interface MonthlyGrowth {
  month: string;
  growth: number;
}

interface SocialStatsData {
  account: AccountData;
  monthlyGrowth: MonthlyGrowth[];
  growthTrend: number[];
}

export default function Widget() {
  const socialStatsData = response.data as SocialStatsData;
  const { account, monthlyGrowth, growthTrend } = socialStatsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: '#F5F5F5' }}>
              {account.platform} Stats
            </Typography>
            <Typography variant="body1" sx={{ color: '#F5F5F5' }}>
              {account.username}
            </Typography>
            <Stack direction="row" spacing={1} sx={{ mt: 1 }}>
              <Chip label={`Followers: ${account.followers}`} sx={{ fontSize: '12px', bgcolor: '#E1306C', color: '#FFFFFF' }} />
              <Chip label={`Engagement: ${account.engagementRate}%`} sx={{ fontSize: '12px', bgcolor: '#405DE6', color: '#FFFFFF' }} />
            </Stack>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: growthTrend,
                color: '#E1306C',
                curve: 'natural',
                showMark: false,
              },
            ]}
            xAxis={[{ data: [0, 1, 2, 3, 4], hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />

          <Box>
            <Typography variant="body2" sx={{ color: '#BDBDBD', mb: 1 }}>
              Monthly Growth
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {monthlyGrowth.map((growth, index) => (
                <Chip
                  key={index}
                  label={`${growth.month}: +${growth.growth}`}
                  sx={{ fontSize: '10px', bgcolor: '#333333', color: '#FFFFFF' }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
